import React from 'react';
import { Bar } from 'react-chartjs-2';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
} from 'chart.js';

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend
);

const DetectionView = () => {
  const rules = [
    { name: 'High Amount Threshold', type: 'rule-based', desc: 'Flag transactions exceeding configurable amount threshold per account tier', triggers: 142, active: true },
    { name: 'Velocity Check', type: 'rule-based', desc: 'Detect multiple transactions within a short time window from the same account', triggers: 89, active: true },
    { name: 'Geo-Location Anomaly', type: 'rule-based', desc: 'Flag transactions from unusual or high-risk geographic locations', triggers: 67, active: true },
    { name: 'Account Behavior Model', type: 'ml-based', desc: 'ML model analyzing deviation from normal account spending patterns', triggers: 203, active: true },
    { name: 'Merchant Blacklist', type: 'rule-based', desc: 'Block transactions from known fraudulent or suspicious merchant IDs', triggers: 31, active: true },
    { name: 'Neural Network Classifier', type: 'ml-based', desc: 'Deep learning model for multi-factor threat probability scoring', triggers: 512, active: false }
  ];

  const chartData = {
    labels: ['Card Not Present', 'Account Takeover', 'Identity Theft', 'Wire Fraud', 'Phishing', 'Chargeback'],
    datasets: [
      {
        label: 'Fraud Count',
        data: [45, 38, 32, 28, 22, 15],
        backgroundColor: '#ef4444',
        borderRadius: 4,
        barThickness: 20
      }
    ]
  };

  const chartOptions = {
    indexAxis: 'y',
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: { display: false }
    },
    scales: {
      x: { grid: { color: '#1e293b' }, ticks: { color: '#64748b' } },
      y: { grid: { display: false }, ticks: { color: '#94a3b8' } }
    }
  };

  return (
    <div style={{ padding: '2rem' }}>
      <h2 style={{ fontSize: '1.5rem', fontWeight: 'bold', marginBottom: '0.5rem' }}>Anomaly Detection & Alerts</h2>
      <p style={{ color: '#94a3b8', marginBottom: '2rem' }}>Configure detection rules, review alerts, and manage fraud prevention strategies</p>

      <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr', gap: '2rem' }}>
        <div style={{ backgroundColor: '#1e293b', padding: '1.5rem', borderRadius: '1rem', border: '1px solid #334155' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
            <h3 style={{ fontSize: '1rem', fontWeight: 'bold' }}>Detection Rules</h3>
            <span style={{ fontSize: '0.875rem', color: '#10b981', fontWeight: 'bold' }}>5 / 6 Active</span>
          </div>

          <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
            {rules.map((rule, i) => (
              <div key={i} style={{ padding: '1.25rem', backgroundColor: '#0f172a', borderRadius: '0.75rem', border: '1px solid #1e293b' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '0.5rem' }}>
                  <div>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', marginBottom: '0.25rem' }}>
                      <p style={{ fontSize: '0.95rem', fontWeight: 'bold' }}>{rule.name}</p>
                      <span style={{ fontSize: '0.7rem', color: '#64748b', backgroundColor: '#1e293b', padding: '0.125rem 0.375rem', borderRadius: '0.25rem', textTransform: 'uppercase' }}>{rule.type}</span>
                    </div>
                    <p style={{ fontSize: '0.8rem', color: '#94a3b8' }}>{rule.desc}</p>
                  </div>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '1rem' }}>
                    <div style={{ textAlign: 'right' }}>
                      <p style={{ fontSize: '0.875rem', fontWeight: 'bold' }}>{rule.triggers}</p>
                      <p style={{ fontSize: '0.7rem', color: '#64748b' }}>Triggers (30d)</p>
                    </div>
                    <div style={{ 
                      width: '40px', 
                      height: '20px', 
                      backgroundColor: rule.active ? '#10b981' : '#334155', 
                      borderRadius: '10px', 
                      position: 'relative',
                      cursor: 'pointer'
                    }}>
                      <div style={{ 
                        width: '16px', 
                        height: '16px', 
                        backgroundColor: 'white', 
                        borderRadius: '50%', 
                        position: 'absolute', 
                        top: '2px', 
                        left: rule.active ? '22px' : '2px',
                        transition: 'left 0.2s'
                      }}></div>
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>

        <div style={{ backgroundColor: '#1e293b', padding: '1.5rem', borderRadius: '1rem', border: '1px solid #334155' }}>
          <h3 style={{ fontSize: '1rem', fontWeight: 'bold', marginBottom: '1.5rem' }}>Fraud by Category (30d)</h3>
          <div style={{ height: '400px' }}>
            <Bar data={chartData} options={chartOptions} />
          </div>
        </div>
      </div>
    </div>
  );
};

export default DetectionView;
